  <div class="toast-container" id="toastContainer"></div>

  <script>
    // ============== Toast ==============
    function showToast(title, message, type = 'success') {
      const container = document.getElementById('toastContainer');
      const toast = document.createElement('div');
      toast.className = `toast ${type}`;
      const icon = type === 'success'
        ? '<svg fill="none" stroke="#16a34a" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>'
        : '<svg fill="none" stroke="#dc2626" viewBox="0 0 24 24" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"/></svg>';
      toast.innerHTML = `${icon}<div class="toast-content"><div class="toast-title">${title}</div><div class="toast-message">${message}</div></div>`;
      container.appendChild(toast);
      setTimeout(() => { toast.style.opacity = '0'; toast.style.transform = 'translateX(120%)'; setTimeout(() => toast.remove(), 300); }, 3500);
    }

    // ============== Toggle Password ==============
    document.querySelectorAll('.password-toggle').forEach(btn => {
      btn.addEventListener('click', () => {
        const input = document.getElementById(btn.dataset.target);
        const isPwd = input.type === 'password';
        input.type = isPwd ? 'text' : 'password';
        btn.classList.toggle('active', isPwd);
      });
    });

    // ============== Editable Inputs ==============
    document.querySelectorAll('.edit-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        const input = btn.previousElementSibling;
        input.removeAttribute('readonly');
        input.focus();
        input.select();
        const finish = () => { input.setAttribute('readonly', true); input.removeEventListener('blur', finish); };
        input.addEventListener('blur', finish);
      });
    });

    // ============== Avatar Upload ==============
    document.querySelector('.avatar-edit').addEventListener('click', () => {
      showToast('Subir foto', 'Funcionalidad de carga de imagen.', 'success');
    });

    // ============== Form Submit ==============
    document.getElementById('profileForm').addEventListener('submit', (e) => {
      e.preventDefault();
      const np = document.getElementById('newPassword').value;
      const cp = document.getElementById('confirmPassword').value;
      if (np || cp) {
        if (np.length < 6) { showToast('Error', 'La contraseña debe tener al menos 6 caracteres.', 'error'); return; }
        if (np !== cp) { showToast('Error', 'Las contraseñas no coinciden.', 'error'); return; }
      }
      showToast('¡Perfil actualizado!', 'Los cambios se guardaron correctamente.');
    });

    // ============== Cancel ==============
    document.querySelector('.btn-secondary').addEventListener('click', () => {
      document.getElementById('profileForm').reset();
      showToast('Cambios descartados', 'El formulario se ha restablecido.');
    });
  </script>

