    .nav-item:hover { background: var(--bg-hover); color: var(--text-primary); }
    .nav-item.active {
      background: var(--lime-soft);
      color: var(--lime);
      box-shadow: inset 2px 0 0 var(--lime);
    }
    .nav-item.active .nav-icon { color: var(--lime); }
    .nav-item svg.nav-icon { width: 17px; height: 17px; flex-shrink: 0; }
    .nav-item .badge {
      margin-left: auto;
      font-family: var(--mono);
      font-size: 10px;
      background: var(--bg-base);
      padding: 2px 7px;
      border-radius: 5px;
      color: var(--text-muted);
    }
    .nav-item.active .badge { background: rgba(200, 255, 58, 0.15); color: var(--lime); }

    /* ==================== Main Content ==================== */
    .content { min-width: 0; }

    /* Hero */
    .hero {
      background: linear-gradient(135deg, var(--bg-raised) 0%, var(--bg-elevated) 100%);
      border: 1px solid var(--line);
      border-radius: var(--radius);
      padding: 28px;
      margin-bottom: 20px;
      position: relative;
      overflow: hidden;
