    .hero::before {
      content: '';
      position: absolute;
      top: -50%; right: -10%;
      width: 400px; height: 400px;
      background: radial-gradient(circle, rgba(200, 255, 58, 0.08) 0%, transparent 60%);
      pointer-events: none;
    }
    .hero-grid {
      display: grid;
      grid-template-columns: auto 1fr auto;
      gap: 24px;
      align-items: center;
      position: relative;
      z-index: 1;
    }

    .hero-avatar {
      width: 96px; height: 96px;
      border-radius: 50%;
      background: linear-gradient(135deg, var(--lime), var(--cyan));
