    .hero-tag::before {
      content: '';
      width: 6px; height: 6px;
      background: var(--lime);
      border-radius: 50%;
      box-shadow: var(--glow-lime);
    }

    .hero-name {
      font-size: 28px;
      font-weight: 700;
      letter-spacing: -0.5px;
      margin-bottom: 4px;
    }
    .hero-name span { color: var(--lime); }

    .hero-subtitle {
      color: var(--text-secondary);
      font-size: 14px;
      display: flex;
      align-items: center;
      gap: 14px;
      flex-wrap: wrap;
    }
    .hero-subtitle .sep { color: var(--text-muted); }

    .hero-actions { display: flex; gap: 10px; }

    .btn {
      height: 42px;
      padding: 0 18px;
      border-radius: 10px;
      font-family: inherit;
      font-size: 13px;
      font-weight: 600;
      cursor: pointer;
      transition: all .2s;
      display: inline-flex;
      align-items: center;
      gap: 8px;
      border: none;
