    .btn-primary:hover { transform: translateY(-1px); box-shadow: 0 0 32px rgba(200, 255, 58, 0.4); }
    .btn-ghost {
      background: transparent;
      color: var(--text-secondary);
      border: 1px solid var(--line-strong);
