    .btn-ghost:hover { background: var(--bg-hover); color: var(--text-primary); }

    /* ==================== Tabs ==================== */
    .tabs-wrapper {
      background: var(--bg-raised);
      border: 1px solid var(--line);
      border-radius: var(--radius);
      padding: 6px;
      display: flex;
      gap: 4px;
      margin-bottom: 20px;
    }

    .tab {
      flex: 1;
      padding: 12px 16px;
      border-radius: 12px;
      cursor: pointer;
      font-size: 13px;
      font-weight: 500;
      color: var(--text-secondary);
      display: flex;
      align-items: center;
      justify-content: center;
      gap: 8px;
      transition: all .2s;
      position: relative;
