    .tab:hover { color: var(--text-primary); background: var(--bg-hover); }
    .tab.active {
      background: var(--bg-elevated);
      color: var(--lime);
      box-shadow: inset 0 0 0 1px var(--lime-soft);
    }
    .tab.active::after {
      content: '';
      position: absolute;
      bottom: -1px;
      left: 50%;
      transform: translateX(-50%);
      width: 24px; height: 2px;
      background: var(--lime);
