    .tab.active .tab-num { color: var(--lime); background: var(--lime-soft); }

    /* ==================== Panels ==================== */
    .panel { display: none; }
    .panel.active { display: block; animation: fadeUp .3s ease; }

    @keyframes fadeUp {
      from { opacity: 0; transform: translateY(8px); }
      to { opacity: 1; transform: translateY(0); }
    }

    .panel-card {
      background: var(--bg-raised);
      border: 1px solid var(--line);
      border-radius: var(--radius);
      padding: 28px;
      margin-bottom: 16px;
    }

    .panel-header {
      display: flex;
      align-items: flex-start;
      justify-content: space-between;
      margin-bottom: 24px;
      padding-bottom: 18px;
      border-bottom: 1px solid var(--line);
    }
    .panel-title {
      font-size: 18px;
      font-weight: 600;
      display: flex;
      align-items: center;
      gap: 10px;
    }
    .panel-title .dot {
      width: 8px; height: 8px;
      background: var(--lime);
      border-radius: 50%;
      box-shadow: var(--glow-lime);
    }
    .panel-subtitle {
      color: var(--text-secondary);
      font-size: 13px;
      margin-top: 4px;
    }

    .field-grid {
      display: grid;
      grid-template-columns: repeat(2, 1fr);
      gap: 16px;
    }

    .field {
      background: var(--bg-base);
      border: 1px solid var(--line);
      border-radius: var(--radius-sm);
      padding: 14px 16px;
      transition: all .2s;
      position: relative;
