    .field-label svg { width: 11px; height: 11px; }
    .field-value {
      font-size: 15px;
      font-weight: 500;
      color: var(--text-primary);
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
    }
    .field-value input {
      flex: 1;
      background: transparent;
      border: none;
      outline: none;
      color: var(--text-primary);
      font-family: inherit;
      font-size: 15px;
      font-weight: 500;
      padding: 0;
    }
    .field-value input:read-only { color: var(--text-secondary); cursor: default; }

    .field-action {
      background: transparent;
      border: none;
      color: var(--text-muted);
      cursor: pointer;
      padding: 4px;
      border-radius: 6px;
      transition: all .2s;
    }
    .field-action:hover { background: var(--lime-soft); color: var(--lime); }
    .field-action svg { width: 14px; height: 14px; }

    .field-pill {
      font-family: var(--mono);
      font-size: 10px;
      background: var(--lime-soft);
      color: var(--lime);
      padding: 3px 8px;
      border-radius: 4px;
      letter-spacing: 0.5px;
    }

    /* ==================== Stats row ==================== */
    .stats-row {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 12px;
      margin-top: 20px;
    }

    .stat {
      background: var(--bg-base);
      border: 1px solid var(--line);
      border-radius: var(--radius-sm);
      padding: 14px 16px;
      display: flex;
      align-items: center;
      gap: 12px;
    }
    .stat-icon {
      width: 38px; height: 38px;
      border-radius: 10px;
      display: flex; align-items: center; justify-content: center;
      flex-shrink: 0;
    }
    .stat-icon svg { width: 18px; height: 18px; }
    .stat-icon.lime { background: var(--lime-soft); color: var(--lime); }
    .stat-icon.cyan { background: rgba(77, 216, 230, 0.12); color: var(--cyan); }
    .stat-icon.magenta { background: rgba(255, 94, 196, 0.12); color: var(--magenta); }

    .stat-info { min-width: 0; }
    .stat-num {
      font-family: var(--mono);
      font-size: 18px;
      font-weight: 600;
      line-height: 1.1;
    }
    .stat-label {
      font-size: 11px;
      color: var(--text-muted);
      margin-top: 2px;
    }

    /* ==================== Toast ==================== */
    .toast-stack {
      position: fixed;
      bottom: 24px;
      right: 24px;
      z-index: 100;
      display: flex;
      flex-direction: column;
      gap: 10px;
    }
    .toast {
      background: var(--bg-elevated);
      border: 1px solid var(--line-strong);
      border-radius: 12px;
      padding: 14px 18px;
      min-width: 280px;
      display: flex;
      align-items: center;
      gap: 12px;
      box-shadow: 0 20px 40px -8px rgba(0, 0, 0, 0.5);
      animation: slideUp .35s cubic-bezier(.16, 1, .3, 1);
