    .toast.success { border-left: 3px solid var(--lime); }
    .toast.error { border-left: 3px solid var(--magenta); }
    .toast svg { width: 18px; height: 18px; flex-shrink: 0; }
    .toast-title { font-size: 13px; font-weight: 600; }
    .toast-msg { font-size: 12px; color: var(--text-secondary); margin-top: 2px; font-family: var(--mono); }

    @keyframes slideUp {
      from { transform: translateY(20px); opacity: 0; }
      to { transform: translateY(0); opacity: 1; }
    }

    /* ==================== Responsive ==================== */
    @media (max-width: 1024px) {
      .layout { grid-template-columns: 1fr; }
      .sidebar { position: static; }
      .search-box { display: none; }
    }

    @media (max-width: 768px) {
      .hero-grid { grid-template-columns: 1fr; text-align: center; }
      .hero-avatar { margin: 0 auto; }
      .hero-actions { justify-content: center; }
      .hero-subtitle { justify-content: center; }
      .field-grid { grid-template-columns: 1fr; }
      .stats-row { grid-template-columns: 1fr; }
      .tabs-wrapper { flex-wrap: wrap; }
      .tab { flex: 1 1 calc(50% - 4px); }
      .panel-card { padding: 20px; }
      .layout { padding: 16px; }
    }
  </style>
