  <div class="toast-stack" id="toastStack"></div>

  <script>
    // ============ Toast ============
    function showToast(title, msg, type = 'success') {
      const stack = document.getElementById('toastStack');
      const t = document.createElement('div');
      t.className = `toast ${type}`;
      const icon = type === 'success'
        ? '<svg fill="none" stroke="#c8ff3a" viewBox="0 0 24 24" stroke-width="2"><circle cx="12" cy="12" r="10"/><path stroke-linecap="round" stroke-linejoin="round" d="M8 12l3 3 5-6"/></svg>'
        : '<svg fill="none" stroke="#ff5ec4" viewBox="0 0 24 24" stroke-width="2"><circle cx="12" cy="12" r="10"/><path stroke-linecap="round" stroke-linejoin="round" d="M12 8v4m0 4h.01"/></svg>';
      t.innerHTML = `${icon}<div><div class="toast-title">${title}</div><div class="toast-msg">${msg}</div></div>`;
      stack.appendChild(t);
      setTimeout(() => {
        t.style.opacity = '0';
        t.style.transform = 'translateY(20px)';
        t.style.transition = 'all .3s';
        setTimeout(() => t.remove(), 300);
      }, 3500);
    }

    // ============ Tabs ============
    const tabs = document.querySelectorAll('.tab');
    const panels = document.querySelectorAll('.panel');
    tabs.forEach(tab => {
      tab.addEventListener('click', () => {
        const target = tab.dataset.tab;
        tabs.forEach(t => t.classList.toggle('active', t === tab));
        panels.forEach(p => p.classList.toggle('active', p.dataset.panel === target));
      });
    });

    document.querySelectorAll('[data-tab-target]').forEach(btn => {
      btn.addEventListener('click', () => {
        const target = btn.dataset.tabTarget;
        const tabEl = document.querySelector(`.tab[data-tab="${target}"]`);
        if (tabEl) tabEl.click();
      });
    });

    // ============ Edit fields ============
    document.querySelectorAll('.edit-btn').forEach(btn => {
      btn.addEventListener('click', () => {
        const input = btn.parentElement.querySelector('input');
        if (input.hasAttribute('readonly')) {
          input.removeAttribute('readonly');
          input.focus();
          input.select();
          const finish = () => {
            input.setAttribute('readonly', true);
            input.removeEventListener('blur', finish);
            showToast('Campo actualizado', input.value || 'Vacío', 'success');
          };
          input.addEventListener('blur', finish);
        }
      });
    });

    // ============ Password toggle ============
    document.querySelectorAll('.password-toggle').forEach(btn => {
      btn.addEventListener('click', () => {
        const input = document.getElementById(btn.dataset.target);
        const isPwd = input.type === 'password';
        input.type = isPwd ? 'text' : 'password';
        btn.style.color = isPwd ? 'var(--lime)' : '';
      });
    });

    // ============ Save personal ============
    document.getElementById('savePersonalBtn').addEventListener('click', () => {
      showToast('Perfil guardado', 'Todos los cambios se aplicaron correctamente.', 'success');
    });

    // ============ Auto-save security ============
    document.getElementById('confirmPassword').addEventListener('blur', () => {
      const np = document.getElementById('newPassword').value;
      const cp = document.getElementById('confirmPassword').value;
      if (np || cp) {
        if (np.length < 8) { showToast('Muy corta', 'Mínimo 8 caracteres.', 'error'); return; }
        if (np !== cp) { showToast('No coinciden', 'Verifica ambas contraseñas.', 'error'); return; }
        showToast('Contraseña actualizada', 'Tu cuenta está segura.', 'success');
      }
    });
  </script>

